/* ===== TOKENS ===== */
:root {
  /* Gray scale — WCAG AA/AAA compliant on white */
  --gray-900: #111827;
  --gray-800: #1f2937;
  --gray-700: #374151;
  --gray-500: #6b7280;
  --gray-400: #9ca3af;
  --gray-200: #e5e7eb;
  --gray-100: #f3f4f6;
  --gray-50: #f9fafb;

  /* Semantic colors */
  --color-text: var(--gray-900);
  --color-text-secondary: var(--gray-700);
  --color-muted: var(--gray-500);
  --color-muted-icon: #888;
  --color-disabled: var(--gray-400);
  --color-border: var(--gray-200);
  --color-surface: var(--gray-100);
  --color-surface-hover: var(--gray-200);
  --color-bg: #fff;
  --color-accent: #b91c1c;
  --color-success: #047857;

  /* Font */
  --font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;

  /* Font scale — em-based, 16px browser default */
  --font-2xl: 2rem;
  --font-xl: 1.5rem;
  --font-lg: 1.125rem;
  --font-base: 1rem;
  --font-sm: 0.875rem;
  --font-xs: 0.75rem;
  --font-2xs: 0.69rem;

  /* Spacing scale — 4px base */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 12px;
  --space-lg: 16px;
  --space-xl: 24px;
  --space-2xl: 32px;

  /* Border radius */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 16px;
  --radius-pill: 999px;

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0,0,0,0.06);
  --shadow-md: 0 2px 8px rgba(0,0,0,0.12);
  --shadow-lg: 0 4px 16px rgba(0,0,0,0.16);
  --shadow-modal: 0 8px 24px rgba(0,0,0,0.12);

  /* Transitions */
  --transition-fast: 0.15s;

  /* Z-index scale */
  --z-sticky: 10;
  --z-header: 40;
  --z-menu-overlay: 47;
  --z-menu: 49;
  --z-modal: 100;
  --z-popup: 200;
  --z-toast: 300;

  /* Layout */
  --header-h: 48px;
}

/* ===== RESET ===== */
*, *::before, *::after { box-sizing: border-box; }

/* ===== BASE ===== */
body {
  font-family: var(--font-family);
  line-height: 1.5;
  margin: 0;
  color: var(--color-text);
  background: var(--color-bg);
}

/* ===== COMPONENTS ===== */

/* --- Hamburger button --- */
.hamburger {
  display: none;
  align-items: center;
  justify-content: center;
  background: none;
  color: #fff;
  border: none;
  width: var(--header-h);
  height: var(--header-h);
  position: absolute;
  right: 0;
  top: 0;
  -webkit-tap-highlight-color: transparent;
  padding: 0;
  cursor: pointer;
}
.hamburger svg {
  width: 24px;
  height: 24px;
  min-width: 24px;
  min-height: 24px;
}

/* --- Cross-page navigation icon --- */
.nav-icon {
  display: none;
  align-items: center;
  justify-content: center;
  color: #fff;
  text-decoration: none;
  width: var(--header-h);
  height: var(--header-h);
  position: absolute;
  left: 0;
  top: 0;
  -webkit-tap-highlight-color: transparent;
  cursor: pointer;
}
.nav-icon svg {
  width: 24px;
  height: 24px;
}

/* --- Menu overlay --- */
.menu-overlay {
  display: none;
}
.menu-overlay.open {
  display: block;
  position: fixed;
  top: var(--header-h);
  left: 0;
  right: 0;
  bottom: 0;
  z-index: var(--z-menu-overlay);
  background: rgba(0,0,0,0.3);
}

/* --- Toast notification --- */
.toast {
  position: fixed;
  bottom: 80px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--gray-900);
  color: #fff;
  padding: var(--space-md) var(--space-xl);
  border-radius: var(--radius-pill);
  font-size: var(--font-sm);
  z-index: var(--z-toast);
  opacity: 0;
  transition: opacity 0.2s;
  pointer-events: none;
  max-width: min(360px, 90vw);
  text-align: center;
  text-wrap: balance;
}
.toast.show { opacity: 1; }

/* ===== UTILITIES ===== */
.truncate {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border-width: 0;
}

/* ===== MOBILE ===== */
@media (max-width: 767px) {
  :root { --header-h: 54px; }
}

