from __future__ import annotations

import logging
import re
import sqlite3
from datetime import datetime, timezone
from urllib.parse import parse_qs, unquote, urlparse

from bs4 import BeautifulSoup
from playwright.sync_api import BrowserContext

from .db import (
    get_artist,
    get_artists_without_platform,
    get_missing_links,
    update_artist_field,
    update_link_follower_count,
    upsert_artist_link,
    PLATFORM_POSITIONS,
)

logger = logging.getLogger(__name__)


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------


def normalize_whitespace(text: str) -> str:
    return " ".join(text.split()) if text else ""


def is_valid_url(url: str | None) -> bool:
    if not url:
        return False
    url = url.strip()
    if not url:
        return False
    try:
        parsed = urlparse(url)
    except Exception:
        return False
    return parsed.scheme in {"http", "https"} and bool(parsed.netloc)


def is_youtube_channel(url: str) -> bool:
    if not url:
        return False
    parsed = urlparse(url)
    host = parsed.netloc.lower().split(":")[0]
    if host != "youtube.com" and not host.endswith(".youtube.com"):
        return False
    path = parsed.path.rstrip("/").lower()
    if any(path.startswith(p) for p in ("/c/", "/channel/", "/user/", "/@")):
        return True
    return False


def is_sc_profile(url: str) -> bool:
    if not url:
        return False
    parsed = urlparse(url)
    host = parsed.netloc.lower().split(":")[0]
    if host == "on.soundcloud.com":
        return False
    if host != "soundcloud.com" and not host.endswith(".soundcloud.com"):
        return False
    segments = [s for s in parsed.path.strip("/").split("/") if s]
    return len(segments) == 1


def parse_follower_count(raw: str | None) -> int | None:
    if not raw:
        return None
    raw = raw.strip().replace(",", "")
    if raw.isdigit():
        return int(raw)
    m = re.match(r"^([\d.]+)([KMB])$", raw, re.IGNORECASE)
    if m:

        score = _ra_match_score(profile, db_artist, db_links)

        has_social_overlap = any(
            _normalize_social_url(profile.get(f))
            and _normalize_social_url(db_links.get(f, ""))
            for f in ("soundcloud", "instagram")
        )
        if has_social_overlap and score >= 3:
            bio = profile.get("biography") or {}
            return {
                "ra_url": f"https://ra.co{profile['contentUrl']}",
                "ra_followers": profile.get("followerCount"),
                "ra_bio": _clean_ra_bio(bio.get("content") or ""),
            }
        if not has_social_overlap and score >= 2:
            bio = profile.get("biography") or {}
            return {
                "ra_url": f"https://ra.co{profile['contentUrl']}",
                "ra_followers": profile.get("followerCount"),
                "ra_bio": _clean_ra_bio(bio.get("content") or ""),
            }

    return None


def fetch_all_ra(ctx: BrowserContext, db: sqlite3.Connection) -> None:
    missing = get_artists_without_platform(db, "ra")
    if not missing:
        return

    total = len(missing)
    print(f"Fetching {total} Resident Advisor profiles ...")

    page = ctx.new_page()
    try:
        page.goto("https://ra.co", wait_until="domcontentloaded", timeout=15000)
        page.wait_for_timeout(2000)

        matched = 0
        for i, artist in enumerate(missing, 1):
            print(f"  [{i}/{total}] RA: {artist['name']}", end="", flush=True)

            artist_links = {
                row["platform"]: row["url"]
                for row in db.execute(
                    "SELECT platform, url FROM artist_links WHERE artist_id = ?",
                    (artist["id"],),
                )
            }
            profile = fetch_ra_profile(page, artist["name"], artist, artist_links)

            if profile:
                matched += 1
                upsert_artist_link(
                    db,
                    artist["id"],
                    "ra",
                    profile["ra_url"],
                    profile["ra_followers"],
                )
                bio = profile["ra_bio"].strip()
                if bio:
                    update_artist_field(db, artist["id"], "bio", bio)
                fc = f"{profile['ra_followers']:,}" if profile["ra_followers"] else "?"
                print(f" -> {fc} followers ({profile['ra_url']})")
            else:
                upsert_artist_link(db, artist["id"], "ra", "", 0)
                print(" -> not found")
    finally:
        page.close()

